21	const STREAM_EXPANDED: Record<string, string> = {
22	  PCMB: 'Physics, Chemistry, Maths & Biology',
23	  PCM: 'Physics, Chemistry & Maths',
24	  PCB: 'Physics, Chemistry & Biology',
25	  PCBZ: 'Physics, Chemistry, Biology & Zoology',
26	  Commerce: 'Commerce / Management',
27	  Humanities: 'Arts / Humanities',
28	};
