32	/**
33	 * SchoolShortReport
34	 * ------------------
35	 * Produces a strictly single-page PDF summary of a school student's
36	 * behavioural profile. Supports SSLC (Class 10) and HSC (Class 12);
37	 * GCSE is routed through the same class via `variant`.
38	 *
39	 * Sections (SSLC):
40	 *   1. Header band
41	 *   2. Report overview (3-line context)
42	 *   3. Where You Fit Best
43	 *   4. Other Available Streams
44	 *   5. Career Flight Path
45	 *   6. Disclaimer + reference to the full report
46	 *
47	 * Sections (HSC):
48	 *   1. Header band
49	 *   2. About this report
50	 *   3. Your Stream (chosen stream + 10-year vision)
51	 *   4. Course Compatibility Matrix (top 3 courses per department)
52	 *   5. Disclaimer
53	 */
54	export class SchoolShortReport extends BaseReport {
55	  private data: SchoolData;
56	  private variant: 'SSLC' | 'HSC' | 'GCSE';
57	  private rankedStreams: { name: string; compat: number }[] = [];
58	  private hscCourses: CourseCompatibility[] = [];
59	  private sslcCourses: CourseCompatibility[] = [];
60	
61	  private readonly CONTENT_X = this.MARGIN_STD;
62	  private readonly CONTENT_W = this.PAGE_WIDTH - 2 * this.MARGIN_STD;
63	
64	  private readonly C_ACCENT_DONT = '#B0381A';
65	  private readonly C_CARD_BG = '#F4F3FB';
66	  private readonly C_CARD_BORDER = '#E0DEF2';
67	  private readonly C_MUTED = '#5D5D70';
68	  private readonly CONTENT_SAFE_BOTTOM = this.PAGE_HEIGHT - 52;
69	
70	  constructor(
71	    data: SchoolData,
72	    options?: PDFKit.PDFDocumentOptions,
73	    variant: 'SSLC' | 'HSC' | 'GCSE' = 'SSLC',
74	  ) {
75	    super(options);
76	    this.data = data;
77	    this.variant = variant;
78	  }
79	
80	  public async generate(outputPath: string): Promise<void> {
81	    logger.info(
82	      `[School SHORT REPORT] Starting ${this.variant} Single-Page PDF...`,
83	    );
84	
85	    if (this.variant === 'HSC') {
86	      await this.preloadHscCourses();
87	    } else {
88	      await this.preloadSslcData();
89	    }
90	
91	    const stream = fs.createWriteStream(outputPath);
92	    this.doc.pipe(stream);
93	
94	    const streamFinished = new Promise<void>((resolve, reject) => {
95	      stream.on('finish', resolve);
96	      stream.on('error', reject);
97	    });
98	
99	    this._useStdMargins = false;
100	    this._currentBackground = null;
101	
102	    if (this.variant === 'HSC') {
103	      this.renderHSC();
104	    } else {
105	      this.renderSSLC();
106	    }
107	
108	    this.doc.end();
109	    await streamFinished;
110	    logger.info(
111	      `[School SHORT REPORT] PDF generated successfully at: ${outputPath}`,
112	    );
113	  }
114	
115	  // ============================================================
116	  // LAYOUT
117	  // ============================================================
118	  private renderSSLC(): void {
119	    const [t1, t2] = this.getTopTwoTraits(
120	      this.data.most_answered_answer_type,
121	      this.data,
122	    );
123	    const combo = t1 + t2;
124	
125	    this.drawPageFrame();
126	
127	    let y = 20;
128	    y = this.drawHeader(y);
129	    y = this.drawOverview(y + 14, combo);
130	    y = this.drawWhereYouFitBest(y + 14, combo);
131	    y = this.drawBestFitVision(y + 26);
132	    y = this.drawCareerFlightPath(y + 26, t1 as 'D' | 'I' | 'S' | 'C', true);
133	    this.drawFooterStrip();
134	
135	    this.doc.addPage();
136	    this.drawPageFrame();
137	
138	    y = this.drawHeader(20);
