152	  // ------------------------------------------------------------
153	  // PRELOAD
154	  // ------------------------------------------------------------
155	  private preloadRankedStreams(): void {
156	    const agile = this.data.agile_scores?.[0];
157	    const agileMap: Record<string, number> = {
158	      Focus: agile?.focus ?? 0,
159	      Courage: agile?.courage ?? 0,
160	      Respect: agile?.respect ?? 0,
161	      Openness: agile?.openness ?? 0,
162	      Commitment: agile?.commitment ?? 0,
163	    };
164	    const topAgile = Object.entries(agileMap).sort(
165	      (a, b) => b[1] - a[1],
166	    )[0]?.[0];
167	
168	    this.rankedStreams = Object.keys(STREAM_AGILE_COMPATIBILITY)
169	      .map((name) => ({
170	        name,
171	        compat:
172	          (STREAM_AGILE_COMPATIBILITY[name] || {})[topAgile || 'Focus'] ?? 65,
173	      }))
174	      .sort((a, b) => b.compat - a.compat);
175	  }
