177	  private async preloadSslcData(): Promise<void> {
178	    this.preloadRankedStreams();
179	
180	    const [t1, t2] = this.getTopTwoTraits(
181	      this.data.most_answered_answer_type,
182	      this.data,
183	    );
184	    const traitCode = t1 + t2;
185	    const bestStreamId = this.getBestFitStreamId();
186	
187	    try {
188	      this.sslcCourses = await getCompatibilityMatrixDetails(
189	        traitCode,
190	        bestStreamId,
191	      );
192	    } catch (err) {
193	      logger.warn(
194	        `[School SHORT REPORT] Failed to fetch SSLC compatible courses`,
195	        err,
196	      );
