201	  private getBestFitStreamId(): number | undefined {
202	    const streamName = this.rankedStreams[0]?.name;
203	    if (!streamName) return undefined;
204	
205	    const entry = Object.entries(STREAM_NAMES).find(
206	      ([, name]) => name === streamName,
207	    );
208	    return entry ? Number(entry[0]) : undefined;
