408	  // ------------------------------------------------------------
409	  // HSC-2b. 10-YEAR VISION ODYSSEY (winding wave timeline)
410	  // ------------------------------------------------------------
411	  private drawOdysseyRoadmap(
412	    boxX: number,
413	    boxY: number,
414	    boxW: number,
415	    boxH: number,
416	    nodes: { label: string; title: string; subtitle: string }[],
417	  ): void {
418	    const startX = boxX + 54;
419	    const endX = boxX + boxW - 54;
420	    const amplitude = 20;
421	    const centerY = boxY + boxH / 2;
422	    const DASHED_LINE_LENGTH = 10;
423	    const TEXT_STACK_GAP = 3;
424	
425	    // Draw winding wave path
426	    this.doc.save();
427	    this.doc
428	      .lineWidth(3)
429	      .strokeColor('#E8EAF6')
430	      .lineJoin('round')
431	      .lineCap('round');
432	
433	    const segments = 80;
434	    for (let j = 0; j <= segments; j++) {
435	      const p = j / segments;
436	      const xp = startX + p * (endX - startX);
437	      const ang = p * Math.PI * 2.5;
438	      const yp = centerY + Math.cos(ang) * amplitude;
439	      if (j === 0) this.doc.moveTo(xp, yp);
440	      else this.doc.lineTo(xp, yp);
441	    }
442	    this.doc.stroke();
443	    this.doc.restore();
444	
445	    // Draw nodes + labels
446	    nodes.forEach((node, i) => {
447	      const progress = i / (nodes.length - 1);
448	      const nodeX = startX + progress * (endX - startX);
449	      const ang = progress * Math.PI * 2.5;
450	      const nodeY = centerY + Math.cos(ang) * amplitude;
451	      const textAbove = i % 2 !== 0;
452	
453	      const nodeR = 6;
454	      let dashEndY: number;
455	      let labelY: number;
456	      let titleY: number;
457	      let subtitleY: number;
458	
459	      const LABEL_W = 95;
460	      const TITLE_W = 108;
461	      const SUB_W = 108;
462	
463	      this.doc.font(this.FONT_SORA_BOLD).fontSize(9);
464	      const labelH = this.doc.heightOfString(node.label, {
465	        width: LABEL_W,
466	        align: 'center',
467	      });
468	      this.doc.font(this.FONT_SORA_SEMIBOLD).fontSize(8);
469	      const titleH = this.doc.heightOfString(node.title, {
470	        width: TITLE_W,
471	        align: 'center',
472	      });
473	      this.doc.font(this.FONT_REGULAR).fontSize(7.2);
474	      const subtitleH = this.doc.heightOfString(node.subtitle, {
475	        width: SUB_W,
476	        align: 'center',
477	      });
478	
479	      if (textAbove) {
480	        dashEndY = nodeY - nodeR - DASHED_LINE_LENGTH;
481	        subtitleY = dashEndY - TEXT_STACK_GAP - subtitleH;
482	        titleY = subtitleY - TEXT_STACK_GAP - titleH;
483	        labelY = titleY - TEXT_STACK_GAP - labelH;
484	      } else {
485	        dashEndY = nodeY + nodeR + DASHED_LINE_LENGTH;
486	        labelY = dashEndY + TEXT_STACK_GAP;
487	        titleY = labelY + labelH + TEXT_STACK_GAP;
488	        subtitleY = titleY + titleH + TEXT_STACK_GAP;
489	      }
490	
491	      // Dashed connector
492	      this.doc
493	        .save()
494	        .lineWidth(1)
495	        .strokeColor('#A0AABF')
496	        .dash(2.5, { space: 2.5 })
497	        .moveTo(nodeX, nodeY + (textAbove ? -nodeR : nodeR))
498	        .lineTo(nodeX, dashEndY)
499	        .stroke()
500	        .restore();
501	
502	      // Node circle
503	      this.doc
504	        .circle(nodeX, nodeY, nodeR)
505	        .fill('#2FB67C')
506	        .lineWidth(2)
507	        .strokeColor('#FFFFFF')
508	        .stroke();
509	
510	      // Label (Year/Phase)
511	      this.doc
512	        .font(this.FONT_SORA_BOLD)
513	        .fontSize(9)
514	        .fillColor(this.COLOR_DEEP_BLUE)
515	        .text(node.label, nodeX - LABEL_W / 2, labelY, {
516	          width: LABEL_W,
517	          align: 'center',
518	          lineBreak: false,
519	        });
520	
521	      // Title
522	      this.doc
523	        .font(this.FONT_SORA_SEMIBOLD)
524	        .fontSize(8)
525	        .fillColor('#2A2A36')
526	        .text(node.title, nodeX - TITLE_W / 2, titleY, {
527	          width: TITLE_W,
528	          align: 'center',
529	          height: titleH,
530	        });
531	
532	      // Subtitle
533	      this.doc
534	        .font(this.FONT_REGULAR)
535	        .fontSize(7.2)
536	        .fillColor('#6B6B78')
537	        .text(node.subtitle, nodeX - SUB_W / 2, subtitleY, {
538	          width: SUB_W,
539	          align: 'center',
540	          height: subtitleH,
541	        });
542	    });
543	  }
