558	  private drawCompatibleCourses(y: number): number {
559	    const streamName = this.rankedStreams[0]?.name ?? 'your best-fit stream';
560	    return this.drawCourseMatrixSection(
561	      y,
562	      this.sslcCourses,
563	      'Compatible Courses for This Stream',
564	      `These course options align with ${streamName}. Review the departments below, then compare the top course matches and percentages to plan your next academic step.`,
565	    );
566	  }
567	
568	  private measureCourseMatrixSection(courses: CourseCompatibility[]): number {
569	    const w = this.CONTENT_W;
570	    const deptMap = new Map<string, CourseCompatibility[]>();
571	    for (const c of courses) {
572	      const dept = (c.department_name || 'General').trim();
573	      if (!deptMap.has(dept)) deptMap.set(dept, []);
574	      deptMap.get(dept).push(c);
575	    }
576	
577	    const depts = Array.from(deptMap.entries())
578	      .slice(0, 4)
579	      .map(([, deptCourses]) =>
580	        deptCourses
581	          .slice()
582	          .sort(
583	            (a, b) => b.compatibility_percentage - a.compatibility_percentage,
584	          )
585	          .slice(0, 3),
586	      );
587	
588	    if (depts.length === 0) return 70;
589	
590	    const colGap = 26;
591	    const rowGap = 8;
592	    const colW = (w - colGap) / 2;
593	    const blockHeights = depts.map((deptCourses) =>
594	      this.measureDeptBlock(colW, deptCourses),
595	    );
596	    const row1H = Math.max(blockHeights[0] ?? 0, blockHeights[1] ?? 0);
597	    const row2H = Math.max(blockHeights[2] ?? 0, blockHeights[3] ?? 0);
598	
599	    return 52 + row1H + (row2H > 0 ? rowGap + row2H : 0);
600	  }
601	
602	  private drawCourseMatrixSection(
603	    y: number,
604	    courses: CourseCompatibility[],
605	    title: string,
606	    description: string,
607	  ): number {
608	    const x = this.CONTENT_X;
609	    const w = this.CONTENT_W;
610	
611	    // Group courses by department preserving insertion order, keep top 3 each.
612	    const deptMap = new Map<string, CourseCompatibility[]>();
613	    for (const c of courses) {
614	      const dept = (c.department_name || 'General').trim();
615	      if (!deptMap.has(dept)) deptMap.set(dept, []);
616	      deptMap.get(dept).push(c);
617	    }
618	    const depts = Array.from(deptMap.entries())
619	      .slice(0, 4)
620	      .map(([name, courses]) => ({
621	        name,
622	        courses: courses
623	          .slice()
624	          .sort(
625	            (a, b) => b.compatibility_percentage - a.compatibility_percentage,
626	          )
627	          .slice(0, 3),
628	      }));
629	
630	    // Section header
631	    this.doc
632	      .font(this.FONT_SORA_BOLD)
633	      .fontSize(13)
634	      .fillColor(this.COLOR_DEEP_BLUE)
