32	/**
33	 * Generates a cryptographically random password of the given length
34	 * drawn from lowercase letters and digits.
35	 */
36	function generateRandomPassword(length: number = 15): string {
37	  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
38	  const bytes = crypto.randomBytes(length);
39	  let result = '';
40	  for (let i = 0; i < length; i++) {
41	    result += chars[bytes[i] % chars.length];
42	  }
43	  return result;
44	}
