46	/**
47	 * Fetches report password settings from the originbi_settings table.
48	 * This is called from a standalone context (not NestJS DI) so it queries
49	 * the DB directly via the existing pg pool.
50	 */
51	async function getReportPasswordSettings(): Promise<{
52	  enabled: boolean;
53	  adminPassword: string;
54	}> {
55	  const pool = getPool();
56	  try {
57	    // Fetch the toggle
58	    const toggleResult = await pool.query(
59	      `SELECT value_boolean FROM originbi_settings WHERE category = 'report' AND setting_key = 'report_password_enabled' LIMIT 1`,
60	    );
61	    const enabled =
62	      toggleResult.rows.length > 0 ? toggleResult.rows[0].value_boolean : true;
63	
64	    // Fetch the admin password
65	    const pwResult = await pool.query(
66	      `SELECT value_string FROM originbi_settings WHERE category = 'report' AND setting_key = 'report_admin_password' LIMIT 1`,
67	    );
68	    const adminPassword =
69	      pwResult.rows.length > 0 ? pwResult.rows[0].value_string || '' : '';
70	
71	    return { enabled: enabled !== false, adminPassword };
72	  } catch (err) {
73	    logger.warn(
74	      `[ReportFactory] Failed to fetch report password settings from DB, falling back to defaults.`,
75	      err,
76	    );
77	    return { enabled: true, adminPassword: '' };
78	  }
79	}
